import React, { useEffect } from "react";
import { useState } from "react";
import itinerariesActions from "../redux/actions/itinerariesActions";
import { useDispatch, useSelector } from "react-redux"
import { useParams } from "react-router-dom";
import FavoriteBorderIcon from '@mui/icons-material/FavoriteBorder';
import FavoriteIcon from '@mui/icons-material/Favorite';
import CardItinerary from './CardItinerary'


let emoji = "💵"

function Itineraries(){

    const [likes, setLikes] = useState()
    // console.log(likes)
    const {id}= useParams()

    const dispatch = useDispatch()

    useEffect(()=>{
        dispatch(itinerariesActions.findTinFromCity(id))
    },[])
    
    const itinerary = useSelector(store=>store.itinerariesReducers.itinerary)
    const user = useSelector(store => store.userReducers.user)

    console.log(itinerary)

    async function likeDislike(id) {
        const like = await dispatch(itinerariesActions.like(id))
        // console.log(id)
        // setLikes(like)
    }

    return(
            <div className="itineraries-container">
                {itinerary.length > 0 ?
                    itinerary.map(itinerary=>(
                    <CardItinerary itinerary={itinerary}/>
                )) : <h1 className="error-tineraries">There are no itineraries here! come back later.</h1>}
            </div>
    )
    console.log(likeDislike);
}
export default Itineraries
